compliant:
public void ExtractArchive(string zipPath, string extractPath)
{
    using (ZipArchive archive = ZipFile.OpenRead(zipPath))
    {
        foreach (ZipArchiveEntry entry in archive.Entries)
        {
            string path = Path.GetFullPath(Path.Combine(extractPath, entry.FullName));
            if (!path.StartsWith(extractPath)) // Compliant
            {
                throw new InvalidOperationException("Zip slip attempt");
            }
            entry.ExtractToFile(path);
        }
    }
}
